/* The AI Agent returns a string in $json.output.
   Parse it and keep only the workflow object for the API call. */

function safeJsonParse(str) {
  try {
    return JSON.parse(str);
  } catch (e) {
    return null;
  }
}

const parsed = safeJsonParse($json.output);

if (!parsed || !parsed.workflow) {
  // If the agent is still asking questions, it may not have returned JSON.
  // Pass through a marker so we can respond gracefully.
  return [{ json: { isReady: false, raw: $json.output } }];
}

return [{ json: { isReady: true, workflow: parsed.workflow, notes: parsed.notes ?? {} } }];

